import {
  ZuploContext,
  ZuploRequest,
  InboundPolicyHandler,
} from "@zuplo/runtime";

const mockApiKeyMetadataPolicy: InboundPolicyHandler = async (
  request: ZuploRequest,
  context: ZuploContext
) => {
  const tenantId = request.headers.get("x-mock-tenant-id");

  if (!tenantId) {
    return new Response("Unauthorized", { status: 401 });
  }

  request.user = {
    sub: "mock-user",
    data: {
      tenantId: tenantId,
    },
  };

  return request;
};

export default mockApiKeyMetadataPolicy;

import { ZuploContext, ZuploRequest } from "@zuplo/runtime";

export default async function (request: ZuploRequest, context: ZuploContext) {
  const tenantId = request.user?.data?.tenantId;

  if (!tenantId) {
    return new Response("Bad Request: tenantId is missing", { status: 400 });
  }

  const upstreamUrl = `https://echo.zuplo.io/${tenantId}/data`;
  const response = await fetch(upstreamUrl);
  return response;
}

